parameters.jsCode:
// 對應 Make: json:ParseJSON + UDT
// 與 Make 差異: 沒有 friendly UI，所有防禦寫進 Code

const raw = $input.first().json.candidates?.[0]?.content?.parts?.[0]?.text || '';

let parsed;
try {
  // 容錯：去掉可能的 ```json 包裹（雖然 prompt 已禁，但保險）
  const cleaned = raw.replace(/```json\s*/i, '').replace(/```\s*$/, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  return [{ json: { tasks: [], _error: 'JSON parse failed', _raw: raw } }];
}

// 防禦：tasks 必為 array
if (!Array.isArray(parsed.tasks)) {
  return [{ json: { tasks: [], _error: 'tasks not array', _parsed: parsed } }];
}

// 防禦：強制 boolean 轉型（避免 LLM 回字串 "true"）
parsed.tasks.forEach(t => {
  if (t.routing) {
    Object.keys(t.routing).forEach(k => {
      t.routing[k] = t.routing[k] === true || t.routing[k] === 'true';
    });
  }
});

return [{ json: parsed }];

